arguments.new_str:
class EnvVarCheck
{
    void CheckFlag()
    {
        // On Linux, set via: export MY_FLAG=""
        // .NET 9 breaking change: empty env vars are no longer treated as unset.
        // Previously GetEnvironmentVariable("MY_FLAG") returned null for "".
        // Now it returns "" — so check both null (unset) and empty (explicitly empty).
        var val = Environment.GetEnvironmentVariable("MY_FLAG");
        if (!Environment.GetEnvironmentVariables().Contains("MY_FLAG"))
        {
            Console.WriteLine("MY_FLAG not set, using default");
        }
    }
}

