arguments.new_str:
using System.IO.Compression;
using System.Text;
class ZipCreator
{
    void CreateArchive()
    {
        // .NET 9 breaking change: ZipArchiveEntry now respects the UTF-8 flag and
        // defaults to UTF-8 encoding for entry names. Our legacy Java consumer
        // expects Shift-JIS encoded filenames. Explicitly specify the encoding to
        // prevent the UTF-8 flag from being set in the entry header.
        using var archive = ZipFile.Open("data.zip", ZipArchiveMode.Create, Encoding.GetEncoding("shift_jis"));
        archive.CreateEntry("レポート/月次.csv");  // Japanese path
        archive.CreateEntry("données/résumé.txt"); // French accented
    }
}

